1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const itemBasePremium = (item: any): number =>
13	  BASE_PREMIUMS[item.type] ?? 0;
14	
15	export function processScenario(scenario: any): any {
16	  const results = scenario.steps.map((step: any) => {
17	    const premium =
18	      step.items.reduce((sum: number, item: any) => sum + itemBasePremium(item), 0) +
19	      PROCESSING_FEE;
20	    return { premium };
21	  });
22	  return { results };
23	}
